#include <stdio.h>

/**
 * @brief Sorts an array using the insertion sort algorithm.
 * @param arr The array of integers to be sorted.
 * @param n The number of elements in the array.
 */
void insertionSort(int arr[], int n) {
    for (int i = 1; i < n; i++) {
        int key = arr[i];
        int j = i - 1;
        while (j >= 0 && arr[j] > key) {
            arr[j + 1] = arr[j];
            j = j - 1;
        }
        arr[j + 1] = key;
    }
}
